void CImage::backward(int mylabel, int delta)
{
    int cid = getComponentIndex(mylabel);
    if(cid < 0 || delta <= 0) {
        return;
    }

    int newPosition = min(components_.size() - 1, static_cast<size_t>(cid) + delta); // Ensure newPosition is not greater than the last index

