    // Create a new blank image array filled with the background color
    uint8_t*** outImage = newImage(bgColor_);

    // Process each component in the list
    for(const auto& comp : components_) {
        // Upper left corner of the component in the original and new locations
        int origRow = comp.ulOrig.row;
        int origCol = comp.ulOrig.col;
        int newRow = comp.ulNew.row;
        int newCol = comp.ulNew.col;

